type driverCountThenLoader[Q orm.Loadable] struct {
	BookingEntries          func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	EventDriverStandings    func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	ResultEntries           func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	SeasonDriverStandings   func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	SimulationDriverAliases func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	TeamDrivers             func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildDriverCountThenLoader[Q orm.Loadable]() driverCountThenLoader[Q] {
	type BookingEntriesCountInterface interface {
		LoadCountBookingEntries(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type EventDriverStandingsCountInterface interface {
		LoadCountEventDriverStandings(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type ResultEntriesCountInterface interface {
		LoadCountResultEntries(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type SeasonDriverStandingsCountInterface interface {
		LoadCountSeasonDriverStandings(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type SimulationDriverAliasesCountInterface interface {
		LoadCountSimulationDriverAliases(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type TeamDriversCountInterface interface {
		LoadCountTeamDrivers(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return driverCountThenLoader[Q]{
		BookingEntries: countThenLoadBuilder[Q](
			"BookingEntries",
			func(ctx context.Context, exec bob.Executor, retrieved BookingEntriesCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountBookingEntries(ctx, exec, mods...)
			},
		),
		EventDriverStandings: countThenLoadBuilder[Q](
			"EventDriverStandings",
			func(ctx context.Context, exec bob.Executor, retrieved EventDriverStandingsCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountEventDriverStandings(ctx, exec, mods...)
			},
		),
		ResultEntries: countThenLoadBuilder[Q](
			"ResultEntries",
			func(ctx context.Context, exec bob.Executor, retrieved ResultEntriesCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountResultEntries(ctx, exec, mods...)
			},
		),
		SeasonDriverStandings: countThenLoadBuilder[Q](
			"SeasonDriverStandings",
			func(ctx context.Context, exec bob.Executor, retrieved SeasonDriverStandingsCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountSeasonDriverStandings(ctx, exec, mods...)
			},
		),
		SimulationDriverAliases: countThenLoadBuilder[Q](
			"SimulationDriverAliases",
			func(ctx context.Context, exec bob.Executor, retrieved SimulationDriverAliasesCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountSimulationDriverAliases(ctx, exec, mods...)
			},
		),
		TeamDrivers: countThenLoadBuilder[Q](
			"TeamDrivers",
			func(ctx context.Context, exec bob.Executor, retrieved TeamDriversCountInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCountTeamDrivers(ctx, exec, mods...)
			},
		),
	}
}

